phase1.code:
using UnityEngine;

// Interface — defines a contract that classes must follow
interface IDamageable
{
    void TakeDamage(int damage);
    bool IsAlive { get; }
}

interface IAttackable
{
    void Attack(IDamageable target);
    int GetAttackPower();
}

interface IInteractable
{
    void Interact();
    string GetInteractionPrompt();
}

// Class implementing multiple interfaces
public class PlayerCharacter : IDamageable, IAttackable
{
    private string name;
    private int health;
    private int maxHealth;
    private int attackPower;

    public PlayerCharacter(string n, int h, int a)
    {
        name = n;
        health = h;
        maxHealth = h;
        attackPower = a;
    }

    // IDamageable implementation
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log(name + " took " + damage + " damage! Health: " + health);
    }

    public bool IsAlive => health > 0;

    // IAttackable implementation
    public void Attack(IDamageable target)
    {
        int damage = attackPower + Random.Range(0, 5);
        Debug.Log(name + " attacks for " + damage + " damage!");
        target.TakeDamage(damage);
    }

    public int GetAttackPower() => attackPower;

    public void DisplayStats()
    {
        Debug.Log("=== Player ===");
        Debug.Log("Name: " + name);
        Debug.Log("Health: " + health + "/" + maxHealth);
        Debug.Log("Attack: " + attackPower);
        Debug.Log("Alive: " + IsAlive);
    }
}

// Another class implementing IDamageable
public class Enemy : IDamageable
{
    private string name;
    private int health;
    private int maxHealth;

    public Enemy(string n, int h)
    {
        name = n;
        health = h;
        maxHealth = h;
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log(name + " took " + damage + " damage! Health: " + health);
    }

    public bool IsAlive => health > 0;

    public void DisplayStats()
    {
        Debug.Log("=== Enemy ===");
        Debug.Log("Name: " + name);
        Debug.Log("Health: " + health + "/" + maxHealth);
        Debug.Log("Alive: " + IsAlive);
    }
}

public class InterfacesExample : MonoBehaviour
{
    void Start()
    {
        PlayerCharacter hero = new PlayerCharacter("Hero", 100, 15);
        Enemy goblin = new Enemy("Goblin", 30);

        hero.DisplayStats();
        goblin.DisplayStats();

        // Polymorphism through interfaces
        IDamageable[] damageables = { hero, goblin };
        foreach (IDamageable d in damageables)
        {
            Debug.Log("Is alive? " + d.IsAlive);
        }

        // Using interface methods
        hero.Attack(goblin);
    }
}

