using UnityEngine;

interface IDamageable
{
    void TakeDamage(int damage);
}

// Forgetting to implement the interface method!
public class Player : IDamageable
{
    public int health;

    // Missing TakeDamage implementation
    // Doesn't implement IsAlive either (not in interface)
}

public class InterfaceError : MonoBehaviour
{
    void Start()
    {
        Player p = new Player();
        // Error: Player doesn't implement IDamageable properly
        // Could still compile, but the interface is useless
    }
}

phase2.explanation:
You declared that `Player` implements `IDamageable`, but you didn't actually write the `TakeDamage` method.

**The fix:**
```csharp
public class Player : IDamageable
{
    public int health;

    public void TakeDamage(int damage)
    {
        health -= damage;
    }
}
```

**Sharp-chan says:**
"If you say you implement an interface, you must implement every method and property in it. No exceptions."
